#### Step 1: Create `userModel.js`

file_ops write_file('userModel.js', `
const mongoose = require('mongoose');
const bcrypt = require('bcrypt');

const userSchema = new mongoose.Schema({
    username: { type: String, required: true, unique: true },
    email: { type: String, required: true, unique: true },
    password: { type: String, required: true },
    resetPasswordToken: String,
    resetPasswordExpires: Date,
});

userSchema.pre('save', async function(next) {
    if (!this.isModified('password')) return next();
    this.password = await bcrypt.hash(this.password, 10);
    next();
});

userSchema.methods.comparePassword = function(password) {
    return bcrypt.compare(password, this.password);
};

const User = mongoose.model('User', userSchema);
module.exports = User;
`)

### Step 2: Create `authController.js`

Now, I will create the authentication controller.

file_ops write_file('authController.js', `
const User = require('./userModel');
const jwt = require('jsonwebtoken');
const nodemailer = require('nodemailer');
const crypto = require('crypto');
const config = require('./config');

exports.register = async (req, res) => {
    const { username, email, password } = req.body;
    try {
        const user = new User({ username, email, password });
        await user.save();
        res.status(201).json({ message: 'User registered successfully' });
    } catch (error) {
        res.status(400).json({ error: error.message });
    }
};

exports.login = async (req, res) => {
    const { email, password } = req.body;
    try {
        const user = await User.findOne({ email });
        if (!user || !(await user.comparePassword(password))) {
            return res.status(401).json({ message: 'Invalid credentials' });
        }
        const token = jwt.sign({ id: user._id }, config.JWT_SECRET, { expiresIn: '1h' });
        res.json({ token });
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
};

exports.logout = (req, res) => {
    res.json({ message: 'User logged out' });
};

exports.resetPassword = async (req, res) => {
    const { email } = req.body;
    try {
        const user = await User.findOne({ email });
        if (!user) {
            return res.status(404).json({ message: 'User not found' });
        }
        const token = crypto.randomBytes(20).toString('hex');
        user.resetPasswordToken = token;
        user.resetPasswordExpires = Date.now() + 3600000; // 1 hour
        await user.save();

        const transporter = nodemailer.createTransport({
            service: 'Gmail',
            auth: {
                user: config.EMAIL_USER,
                pass: config.EMAIL_PASS,
            },
        });

        const mailOptions = {
            to: user.email,
            from: config.EMAIL_USER,
            subject: 'Password Reset',
            text: 'Click the link to reset your password: ' + 
                  `http://localhost:3000/reset/${token}`,
        };

        await transporter.sendMail(mailOptions);
        res.json({ message: 'Password reset link sent' });
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
};
`)

### Step 3: Create `authRoutes.js`

Next, I will create the routes for authentication.

file_ops write_file('authRoutes.js', `
const express = require('express');
const { register, login, logout, resetPassword } = require('./authController');
const router = express.Router();

router.post('/register', register);
router.post('/login', login);
router.post('/logout', logout);
router.post('/reset', resetPassword);

module.exports = router;
`)

### Step 4: Create `authMiddleware.js`

Now, I will create the authentication middleware.

file_ops write_file('authMiddleware.js', `
const jwt = require('jsonwebtoken');
const config = require('./config');

exports.isAuthenticated = (req, res, next) => {
    const token = req.headers['authorization'];
    if (!token) {
        return res.status(401).json({ message: 'No token provided' });
    }
    jwt.verify(token, config.JWT_SECRET, (err, decoded) => {
        if (err) {
            return res.status(401).json({ message: 'Unauthorized' });
        }
        req.userId = decoded.id;
        next();
    });
};
`)

### Step 5: Create `config.js`

Next, I will create the configuration file.

file_ops write_file('config.js', `
module.exports = {
    JWT_SECRET: 'your_jwt_secret',
    EMAIL_USER: 'your_email@gmail.com',
